<td>\u5FEB\u6377\u5217\u8868\uFF0C\u652F\u6301\u4F7F\u7528 <code>[&#39;today&#39;, &#39;yesterday&#39;, &#39;-3&#39;, &#39;-7&#39;, &#39;week&#39;, &#39;lastWeek&#39;, &#39;month&#39;, &#39;lastMonth&#39;, &#39;year&#39;]</code> \u6765\u8868\u793A</td>
